// Pega o primeiro resultado do SQL
const row = $input.first()?.json;

if (!row) {
  return [{
    json: {
      success: false,
      error: 'No gold price data found in database',
      timestamp: new Date().toISOString()
    }
  }];
}

// Formata a resposta limpa para o site consumir
return [{
  json: {
    success: true,
    data: {
      material:    row.Material    ?? 'oro',
      carati:      row.Carati      ?? 24,
      valor_grama: parseFloat((row.valor_grama ?? 0).toFixed(4)),
      oz_price:    parseFloat((row.oz_price    ?? 0).toFixed(4)),
      usd_eur:     parseFloat((row.usd_eur     ?? 0).toFixed(6)),
      rate_date:   row.rate_date   ?? null,
      updated_at:  row.updated_at  ?? null
    },
    source: 'Gold feed via N8N',
    fetched_at: new Date().toISOString()
  }
}];

