### The developer of client-site.example adds to the website:
It runs every 10 minutes.

setInterval(async () => {
  const res = await fetch('https://<seu-n8n>/webhook/ouro/atual');
  const { data } = await res.json();
  document.getElementById('preco-ouro').textContent = data.oz_price.toFixed(2) + ' €/oz';
}, 10 * 60 * 1000);
